// A second rewrite-path module (const -> let demotion) whose dynamic import
// carries a webpack magic comment: webpackIgnore tells webpack to leave the
// import() alone at runtime instead of bundling ./lazy.js into a chunk. If
// the rewrite dropped the comment, webpack would emit an extra chunk and
// the literal './lazy.js' specifier would vanish from the bundle.
export const handler = async (event) => `lz:${event}`;

export function lazy() {
  return import(/* webpackIgnore: true */ './lazy.js');
}
